65	// Shrink the size of the local queue when using loom. This shouldn't impact
66	// logic, but allows loom to test more edge cases in a reasonable a mount of
67	// time.
68	#[cfg(loom)]
69	const LOCAL_QUEUE_CAPACITY: usize = 4;
