88	    let inner = Arc::new(Inner {
89	        head: AtomicUnsignedLong::new(0),
90	        tail: AtomicUnsignedShort::new(0),
91	        buffer: make_fixed_size(buffer.take(LOCAL_QUEUE_CAPACITY).collect()),
92	    });
